            log4(mark, 288,                           // calldata

                 shl(224, shr(224, calldataload(0))), // msg.sig

                 caller,                              // msg.sender

                 calldataload(4),                     // arg1

                 calldataload(36)                     // arg2

                )

        }

    }

}



